#include <string>
#include <cmath>

using namespace std;

#define MAX 1000000007

// Functie pentru calculul eficient al puterii
long long power(long long base, long long exp) {
    long long result = 1;
    // Reducem baza la modulo MAX pentru a evita overflow-ul
    base %= MAX;
    while (exp > 0) {
        if (exp % 2 == 1)  // Daca exponentul este impar
            // Inmultim rezultatul cu baza
            result = (result * base) % MAX;
        base = (base * base) % MAX;;
        // Exponentul devine partea intreaga a impartirii
        exp /= 2;
    }
    return result;
}

int main() {
    ifstream in_file("colorare.in");
    ofstream out_file("colorare.out");

    long long res = 1;
    // Variabila ce retine tipul de colorare pe iteratia precedenta
    string prev;
    int K;

    in_file >> K;
    for (int i = 0; i < K; i++) {
        int X;
        string T;
        in_file >> X >> T;

        if (i == 0) {  // Pentru prima iteratie
            if (T == "H") {
                    res = 6 * power(3, X-1);
                    res = res % MAX;
                    prev = "H";
            } else if (T == "V") {
                    res = 3 * power(2, X-1);
                    res = res % MAX;
                    prev = "V";
            }
        } else {  // Pentru toate celelalte iteratii
            // Tinem cont de colorarea curenta si cea precedenta
            if (T == "H") {
                    if (prev == "H") {
                        res = res * power(3, X);
                        res = res % MAX;
                    } else if (prev == "V") {
                        res = res * 2 * power(3, X-1);
                        res = res % MAX;
                    }
                    prev = "H";
                } else if (T == "V") {
                    if (prev == "H") {
                        res = res * 1 * power(2, X-1);
                        res = res % MAX;
                    } else if (prev == "V") {
                        res = res * power(2, X);
                        res = res % MAX;
                    }
                    prev = "V";
                }
        }
    }
    in_file.close();

    out_file << res << endl;
    out_file.close();

    return 0;
}

import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;


public class Colorare {
	static int k;
	static int[] X;
	static char[] T;
	static final int MOD = 1000000007;

	public static void main(String[] args) {
		String inputFilename = "colorare.in";
		String outputFilename = "colorare.out";

		// citirea din fisier
		readInput(inputFilename);

		// calcularea si printarea rezultatului in fisier
		long result = calculatePossibilities();
		writeOutput(outputFilename, result);
	}

	// metoda de printare in fisier
	private static void writeOutput(String filename, long output) {
		try (BufferedWriter bufferedWriter = new BufferedWriter(new FileWriter(filename))) {
			String formattedNumber = String.format("%d\n", output);
			bufferedWriter.write(formattedNumber);
		} catch (Exception e) {
			e.printStackTrace();
		}
	}

	// metoda de citire din fisier
	private static void readInput(String filename) {
		try (BufferedReader bufferedReader = new BufferedReader(new FileReader(filename))) {
			k = Integer.parseInt(bufferedReader.readLine()); // numarul de perechi
			X = new int[k]; // numarul de dreptunghiuri
			T = new char[k]; // pozitia dreptunghiurilor
			String[] elements = bufferedReader.readLine().split(" ");
			// parcurgem tot vectorul si elementele cu index par, reprezentate de numere,
			// vor fi retinute in X, iar cele cu index impar,
			// reprezentate de caractere(V sau H), vor fi retinute in T.
			// Fiecare pereche va avea index comun pentru vectorul aferent
			for (int i = 0; i < 2 * k; i = i + 2) {
				X[i / 2] = Integer.parseInt(elements[i]);
				T[i / 2] = elements[i + 1].charAt(0);
			}
		} catch (IOException e) {
			e.printStackTrace();
		}
	}

	// metoda de calculare a numarului de tablouri distincte care se pot realiza
	private static long calculatePossibilities() {
		// initializam cu 1 pentru a fi neutru inmultirii
		long result = 1;

		// tratam separat prima pereche pentru ca primul dreptunghi
		// va avea o varianta in plus de culoare
		// fata de restul dreptunghiurilor
		if (T[0] == 'H') {
			result = ((result % MOD) * ((long) (3 * 2 * power(3, X[0] - 1)) % MOD)) % MOD;
		} else {
			result = ((result % MOD) * ((long) (3 * power(2, X[0] - 1)) % MOD)) % MOD;
		}

		// pentru fiecare pereche vom calcula numarul de posibilitati folosind formula,
		// in functie si de caracterul precedent
		// (daca dreptunghiul precedent a fost vertical sau orizontal)
		for (int i = 1; i < k; i++) {
			if (T[i] == 'H' && T[i - 1] == 'H') {
				result = ((result % MOD) * ((long) (power(3, X[i])) % MOD)) % MOD;
			} else if (T[i] == 'H' && T[i - 1] == 'V') {
				result = ((result % MOD) * ((long) (2 * power(3, X[i] - 1)) % MOD)) % MOD;
			} else if (T[i] == 'V' && T[i - 1] == 'H') {
				result = ((result % MOD) * ((long) (power(2, X[i] - 1)) % MOD)) % MOD;
			} else if (T[i] == 'V' && T[i - 1] == 'V') {
				result = ((result % MOD) * ((long) (power(2, X[i])) % MOD)) % MOD;
			}
		}

		return result;
	}

	// https://www.geeksforgeeks.org/write-a-c-program-to-calculate-powxn/
	// Program to calculate pow(x,n) using Binary operators
	// metoda de ridicare la putere in timp logaritmic
	public static long power(long base, long exponent) {
		long result = 1;
		while (exponent > 0) {
			if (exponent % 2 != 0) { // exponentul este impar
				result = ((result % MOD) * (base % MOD)) % MOD;
			}
			base = ((base % MOD) * (base % MOD)) % MOD;
			exponent = exponent >> 1; // injumatatim exponentul
		}
		return result;
	}
}
